example.code:
// Lead form submission
fbq('track', 'Lead', {
  value: 50.00,
  currency: 'USD'
});

// Purchase with dynamic value
fbq('track', 'Purchase', {
  value: 99.00,
  currency: 'USD',
  content_ids: ['prod_123'],
  content_type: 'product'
});

// Add to cart
fbq('track', 'AddToCart', {
  value: 49.99,
  currency: 'USD',
  content_ids: ['SKU123'],
  content_type: 'product'
});
